domain_model:
{
  "packageBase": "com.application",
  "boundedContexts": [
    {
      "name": "Gestión Académica y Administrativa",
      "modules": [
        {
          "name": "alumno",
          "entities": [
            {
              "name": "Alumno",
              "attributes": ["id", "numeroMatricula", "nombre", "apellidos", "fechaNacimiento", "fechaAlta", "activo"],
              "rules": ["El número de matrícula debe ser único", "Un alumno debe tener al menos un tutor asociado al darse de alta", "La fecha de alta no puede ser futura"]
            },
            {
              "name": "Tutor",
              "attributes": ["id", "nombre", "apellidos", "documentoIdentidad", "telefono", "email", "relacionConAlumno"],
              "rules": ["Debe proporcionarse al menos un método de contacto (teléfono o email)", "El documento de identidad debe ser único por tutor"]
            }
          ],
          "valueObjects": [
            {
              "name": "Direccion",
              "attributes": ["linea1", "linea2", "codigoPostal", "ciudad", "provincia"]
            },
            {
              "name": "DocumentoIdentidad",
              "attributes": ["tipo", "numero", "paisEmision"],
              "rules": ["El número debe ser válido según el tipo y país"]
            }
          ],
          "aggregates": [
            {
              "root": "Alumno",
              "entities": ["Tutor"],
              "rules": ["Un Alumno puede tener uno o más Tutores", "La eliminación de un Alumno marca su estado como 'inactivo', no borra físicamente"]
            }
          ]
        },
        {
          "name": "asistencia",
          "entities": [
            {
              "name": "RegistroAsistencia",
              "attributes": ["id", "fecha", "horaEntrada", "horaSalida", "estado", "comentarios"],
              "rules": ["La hora de entrada no puede ser posterior a la hora de salida", "La fecha del registro no puede ser futura", "El estado es obligatorio (PRESENTE, AUSENTE, JUSTIFICADO, RETRASO)"]
            }
          ],
          "valueObjects": [
            {
              "name": "EstadoAsistencia",
              "attributes": ["valor"],
              "rules": ["Debe ser uno de los valores predefinidos: PRESENTE, AUSENTE, JUSTIFICADO, RETRASO"]
            }
          ],
          "aggregates": [
            {
              "root": "RegistroAsistencia",
              "entities": [],
              "rules": ["Cada RegistroAsistencia pertenece a un único Alumno en una fecha específica", "No puede haber más de un registro por alumno y fecha"]
            }
          ]
        },
        {
          "name": "facturacion",
          "entities": [
            {
              "name": "Factura",
              "attributes": ["id", "numeroFactura", "fechaEmision", "fechaVencimiento", "periodoFacturadoInicio", "periodoFacturadoFin", "total", "estado", "concepto"],
              "rules": ["El número de factura debe ser único", "La fecha de vencimiento debe ser posterior a la de emisión", "El periodo facturado debe ser un mes natural", "El estado es obligatorio (GENERADA, ENVIADA, PAGADA, PENDIENTE, CANCELADA)", "El total debe ser mayor o igual a cero"]
            },
            {
              "name": "LineaFactura",
              "attributes": ["id", "concepto", "cantidad", "precioUnitario", "importe"],
              "rules": ["La cantidad debe ser mayor a cero", "El precio unitario debe ser mayor o igual a cero", "El importe se calcula como cantidad * precio unitario"]
            },
            {
              "name": "Tarifa",
              "attributes": ["id", "nombre", "descripcion", "precioMensual", "activo", "fechaInicio", "fechaFin"],
              "rules": ["El precio mensual debe ser mayor a cero", "Las fechas de vigencia no deben solaparse para tarifas del mismo tipo", "Solo una tarifa por tipo puede estar activa a la vez"]
            }
          ],
          "valueObjects": [
            {
              "name": "Dinero",
              "attributes": ["cantidad", "divisa"],
              "rules": ["La cantidad no puede ser negativa", "La divisa debe ser un código ISO válido (ej: EUR)"]
            },
            {
              "name": "Periodo",
              "attributes": ["fechaInicio", "fechaFin"],
              "rules": ["La fecha de inicio debe ser anterior o igual a la fecha de fin"]
            }
          ],
          "aggregates": [
            {
              "root": "Factura",
              "entities": ["LineaFactura"],
              "rules": ["Una Factura tiene una o más LineaFactura", "El total de la Factura es la suma del importe de sus líneas", "Una Factura pertenece a un único Alumno/Tutor"]
            },
            {
              "root": "Tarifa",
              "entities": [],
              "rules": ["Los cambios en una Tarifa activa no afectan a Facturas ya emitidas"]
            }
          ]
        },
        {
          "name": "colegio",
          "entities": [
            {
              "name": "Colegio",
              "attributes": ["id", "nombre", "codigoCentro", "direccion", "telefono", "email"],
              "rules": ["El código de centro debe ser único", "Debe proporcionarse al menos un método de contacto"]
            },
            {
              "name": "Clase",
              "attributes": ["id", "nombre", "nivelEducativo", "anoAcademico", "capacidadMaxima"],
              "rules": ["El nombre debe ser único dentro del mismo nivel y año académico", "La capacidad máxima debe ser mayor a cero"]
            }
          ],
          "valueObjects": [
            {
              "name": "CodigoCentroEducativo",
              "attributes": ["codigo"],
              "rules": ["Debe seguir el formato oficial del país/región"]
            }
          ],
          "aggregates": [
            {
              "root": "Colegio",
              "entities": ["Clase"],
              "rules": ["Un Colegio tiene una o más Clases", "La eliminación de un Colegio es lógica (desactivación)"]
            }
          ]
        }
      ],
      "domainEvents": [
        {
          "name": "AlumnoMatriculado",
          "attributes": ["alumnoId", "numeroMatricula", "fechaMatricula", "claseId"]
        },
        {
          "name": "AsistenciaRegistrada",
          "attributes": ["alumnoId", "registroAsistenciaId", "fecha", "estado"]
        },
        {
          "name": "FacturaGenerada",
          "attributes": ["facturaId", "numeroFactura", "alumnoId", "total", "fechaVencimiento"]
        },
        {
          "name": "FacturaPagada",
          "attributes": ["facturaId", "fechaPago", "importePagado"]
        }
      ],
      "policies": [
        {
          "name": "Política de Generación de Factura Mensual",
          "rule": "El último día de cada mes, se genera automáticamente una factura para cada alumno activo con la tarifa asignada vigente."
        },
        {
          "name": "Política de Control de Asistencia",
          "rule": "Si un alumno acumula más de 3 ausencias no justificadas en un mes, se notifica automáticamente a sus tutores."
        }
      ]
    }
  ]
}
